  ('disabled-6f0ba476-moex-00119', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-f6c431ec', 'sub-disabled-6f0ba476-05', NULL, 'single_choice', '假設社會上僅有A與B二人，且其對某一財貨的個人需求曲線均為P＋Q＝100， 其中P為價格，Q為數量。下列敘述何者正確？', '["若此財貨為公共財，則社會的總需求曲線為P＋2Q＝200", "若此財貨為公共財，則社會的總需求曲線為2P＋Q＝100", "若此財貨為私有財，則社會的總需求曲線為2P＋Q＝200", "若此財貨為私有財，則社會的總需求曲線為P＋2Q＝100"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "d8d8bfd5e7fd", "answer_pdf_sha1": "71660b65fc40", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
